INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Lengua y Literatura', 'Competencia 1: Utiliza el lenguaje como el medio que le permite establecer relaciones en los diferentes ámbitos en los que se desenvuelve.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Lengua y Literatura', 'Competencia 2: Aplica diferentes estrategias de lectura que le permiten generar significados de los textos que lee.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Lengua y Literatura', 'Competencia 3: Valora la literatura hispanoamericana como aporte cultural universal.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Lengua y Literatura', 'Competencia 4: Redacta diversos tipos de texto, tomando en cuenta la intención comunicativa.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Lengua y Literatura', 'Competencia 5: Redacta diversos tipos de texto, tomando en cuenta la intención comunicativa.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Lengua y Literatura', 'Competencia 6: Utiliza recursos diversos en la obtención de información y en la expresión de sus acuerdos o desacuerdos (argumentos).', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Comunicación y Lenguaje L3 (Inglés Técnico)', 'Competencia 1: Engages in conversations and exchanges information and opinions orally and in writing.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Comunicación y Lenguaje L3 (Inglés Técnico)', 'Competencia 2: Understands and interprets the written and spoken language on a variety of topics in the target language.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Comunicación y Lenguaje L3 (Inglés Técnico)', 'Competencia 3: Presents information, concepts, and ideas to an audience of listeners or readers.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Comunicación y Lenguaje L3 (Inglés Técnico)', 'Competencia 4: Applies in his/her relationships with others his understanding of cultural practices other than his/her own.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Tecnologías de la Información y la Comunicación', 'Competencia 1: Explica las funciones básicas de un computador personal y su sistema operativo para una correcta operación.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Tecnologías de la Información y la Comunicación', 'Competencia 2: Emplea las TICs para estructurar, verificar, refinar y presentar la información en una forma adecuada para su procesamiento y presentación para diversos propósitos y audiencias específicas.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Tecnologías de la Información y la Comunicación', 'Competencia 3: Selecciona las fuentes adecuadas de información y herramientas de las TICs para tareas específicas, teniendo en cuenta la facilidad de uso y conveniencia, diseñando métodos adecuados para recopilar y preparar información para su procesamiento e implementación de sistemas para uso de otros.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Tecnologías de la Información y la Comunicación', 'Competencia 4: Clasifica paquetes de software y los modelos basados en las TICs, en el análisis de las situaciones para las que fueron desarrolladas para evaluar su eficiencia, facilidad de uso y conveniencia, sugiriendo mejoras a los sistemas existentes, documentando la existencia de nuevos sistemas para uso de otros.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Matemáticas', 'Competencia 1: Produce patrones aritméticos, algebraicos y geométricos aplicando propiedades, relaciones, figuras geométricas, símbolos y señales de fenómenos naturales, sociales y culturales.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Matemáticas', 'Competencia 2: Plantea y resuelve situaciones problemas de carácter formal que demandan el dominio del pensamiento lógico matemático y las operaciones matemáticas de aritmética y álgebra en los conjuntos numéricos reales y complejos.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Matemáticas', 'Competencia 3: Aplica conocimientos sobre funciones, matrices, geometría y vectores, en situaciones que promueven el mejoramiento y transformación del medio natural, social y cultural de su contexto.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Matemáticas', 'Competencia 4: Utiliza técnicas de sucesiones y series para interpretar hechos sociales, económicos y geográficos.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Matemáticas', 'Competencia 5: Emplea las teorías de geometría y trigonometría para interpretar informaciones y elaborar informes sobre situaciones reales.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Ciencias Sociales y Formación Ciudadana', 'Competencia 1: Aplica leyes, categorías y conceptos de las ciencias sociales en la interpretación de los fenómenos sociales derivados de la globalización económica, política, cultural y tecnológica.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Ciencias Sociales y Formación Ciudadana', 'Competencia 2: Promueve la participación para la construcción de una sociedad democrática, basada en el consenso, el compromiso individual y colectivo.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Ciencias Sociales y Formación Ciudadana', 'Competencia 3: Maneja selectiva y rigurosamente la información, utilizando sus capacidades de análisis crítico, interpretación, sistematización y pensamiento indagador en la solución de problemas.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Ciencias Sociales y Formación Ciudadana', 'Competencia 4: Valora las interrelaciones entre distintas culturas y comprenderá el significado de las identidades culturales y de la soledad.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Física', 'Competencia 1: Utiliza el cálculo vectorial para la interpretación de cantidades físicas que interactúan en su ambiente natural.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Física', 'Competencia 2: Aplica razones físicas espacio-temporales del movimiento o trayectoria de un cuerpo en una y dos dimensiones, así como las leyes de Newton del movimiento mecánico de los cuerpos, el teorema del trabajo, energía y la potencia (cinemática), en la resolución de problemas de su entorno.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Física', 'Competencia 3: Aplica los principios de conservación de la cantidad de movimiento y de conservación de la energía en problemas de choques de cuerpos inelásticos y elásticos en situaciones de la vida cotidiana.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Física', 'Competencia 4: Aplica los principios de la energía en la resolución de problemas de su vida cotidiana.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Educación Física', 'Competencia 1: Fortalece la capacidad física de la resistencia y desarrolla la habilidad de la táctica individual del Baloncesto.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Educación Física', 'Competencia 2: Fortalece la capacidad física de la fuerza máxima y desarrolla la habilidad de la táctica individual del Fútbol.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Educación Física', 'Competencia 3: Fortalece la capacidad física de la rapidez y desarrolla la habilidad de la táctica individual del Balonmano.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Educación Física', 'Competencia 4: Fortalece la capacidad física de la agilidad y desarrolla la habilidad de los elementos técnicos de la danza aeróbica.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Filosofía', 'Competencia 1: Reconoce la importancia de dar significado a la existencia de la persona, el desarrollo social, político y cultural en Guatemala.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Filosofía', 'Competencia 2: Utiliza las reglas del razonamiento válido, basado en la lógica formal, en los ámbitos del conocimiento científico y de la práctica ciudadana.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Filosofía', 'Competencia 3: Emite opinión sobre los problemas y efectos colaterales de la ciencia, la tecnología y sus implicaciones en la vida social y cultural.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Filosofía', 'Competencia 4: Describe la vivencia de la experiencia estética y el proceso creativo vinculado al arte en sus distintas expresiones y reflexiona sobre el fenómeno estético.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Filosofía', 'Competencia 5: Identifica los principales problemas que abordan los filósofos y pensadores guatemaltecos y centroamericanos como parte de la historia de la filosofía.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Psicología', 'Competencia 1: Reflexiona sobre la aplicación a nivel personal y social de la base conceptual de la psicología.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Psicología', 'Competencia 2: Compara las "escuelas psicológicas" en relación con el contexto histórico, filosófico y social.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Psicología', 'Competencia 3: Proyecta el conocimiento de las bases de las escuelas psicológicas a su realidad como persona y como futuro profesional.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Psicología', 'Competencia 4: Aplica los métodos de la psicología a situaciones educativas y de investigación.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Psicología', 'Competencia 5: Identifica las diferencias individuales manifestadas a través de la personalidad de quienes le rodean y de su propia expresión personal, en situaciones reales.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Psicología', 'Competencia 6: Proyecta el conocimiento de los rasgos y temperamentos a su vida y de quienes le rodean.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Psicología', 'Competencia 7: Estructura formas de atender y prevenir, a nivel físico y psíquico, los trastornos de personalidad más comunes en la población de adolescentes y adultos.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Psicología', 'Competencia 8: Adquiere los principios básicos para el desarrollo de una sexualidad sana y responsable.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Elaboración y Gestión de Proyectos', 'Competencia 1: Determina los problemas por medio de técnicas y procedimientos adecuados para el estudio.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Elaboración y Gestión de Proyectos', 'Competencia 2: Utiliza los conceptos básicos de la formulación de proyectos para la solución de problemas en que se encuentra inmerso.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Elaboración y Gestión de Proyectos', 'Competencia 3: Emplea modalidades y técnicas de la planificación como inicio de la gestión de proyectos en la ejecución del proyecto.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Elaboración y Gestión de Proyectos', 'Competencia 4: Emplea la planificación como inicio de la gestión de proyectos en la formulación y ejecución de su proyecto.', ARRAY[]::TEXT[]);
INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras - Quinto Año', 'Lengua y Literatura', 'Competencia 1: Utiliza el lenguaje como una actividad mediante la cual, usando los signos de la lengua, expresa sus pensamientos y satisface una necesidad de comunicación.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Lengua y Literatura', 'Competencia 2: Aplica sus habilidades lectoras con sentido crítico al seleccionar información importante en todo contexto.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Lengua y Literatura', 'Competencia 3: Redacta diversos tipos de texto, tomando en cuenta la situación comunicativa.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Lengua y Literatura', 'Competencia 4: Utiliza los componentes del lenguaje como los medios que le permiten reafirmar sus pensamientos, ampliar sus conocimientos y satisfacer necesidades de comunicación y recreación.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Lengua y Literatura', 'Competencia 5: Aplica la normativa vigente del español en su discurso, tanto oral como escrito.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Comunicación y Lenguaje L3 (Inglés Técnico)', 'Competencia 1: Participates in conversations exchanging information and opinions orally and written.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Comunicación y Lenguaje L3 (Inglés Técnico)', 'Competencia 2: Interprets written and spoken language on a variety of topics.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Comunicación y Lenguaje L3 (Inglés Técnico)', 'Competencia 3: Promotes the analysis of information, concepts, and ideas.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Comunicación y Lenguaje L3 (Inglés Técnico)', 'Competencia 4: Usa responsablemente las TICs como medio de comunicación interpersonal en grupos (chats, foros...).', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Comunicación y Lenguaje L3 (Inglés Técnico)', 'Competencia 5: Desarrolla una actitud abierta, responsable y crítica ante las aportaciones de las nuevas tecnologías (contenidos, entretenimiento).', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Tecnologías de la Información y la Comunicación', 'Competencia 1: Usa los navegadores de Internet (navegar, almacenar, recuperar, clasificar e imprimir información).', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Tecnologías de la Información y la Comunicación', 'Competencia 2: Utiliza los buscadores para localizar información específica en Internet.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Tecnologías de la Información y la Comunicación', 'Competencia 3: Envía y recibe mensajes de correo electrónico, organiza la libreta de direcciones y sabe adjuntar archivos.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Matemáticas', 'Competencia 1: Aplica teoremas trigonométricos, senos y cosenos en la interpretación de funciones trigonométricas circulares.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Matemáticas', 'Competencia 2: Emplea las funciones exponenciales y logarítmicas para representaciones gráficas.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Matemáticas', 'Competencia 3: Utiliza las funciones polinomiales y racionales para explicar fenómenos de la realidad social, económica.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Matemáticas', 'Competencia 4: Aplica el álgebra matricial para la solución de problemas de la vida real.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Matemáticas', 'Competencia 5: Utiliza el cálculo integral para determinar velocidades instantáneas, área bajo las curvas y volumen para cuerpos sólidos.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Estadística Descriptiva', 'Competencia 1: Utiliza la información obtenida por medio de la aplicación de diferentes procedimientos estadísticos descriptivos en la toma de decisiones.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Estadística Descriptiva', 'Competencia 2: Interpreta la información estadística de diferentes fuentes para enriquecer su labor docente.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Estadística Descriptiva', 'Competencia 3: Utiliza la tecnología existente en el análisis estadístico.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Ciencias Sociales y Formación Ciudadana', 'Competencia 1: Identifica las características de la sociedad contemporánea guatemalteca, a partir de diversas perspectivas, su origen y multicausalidad.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Ciencias Sociales y Formación Ciudadana', 'Competencia 2: Propone estrategias que permitan la construcción de un Estado incluyente y democrático, a partir de la descripción de los problemas fundamentales que generan la exclusión.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Ciencias Sociales y Formación Ciudadana', 'Competencia 3: Promueve la vivencia y respeto de los derechos y deberes establecidos en el marco jurídico interno y los convenios y tratados internacionales en materia de derechos humanos.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Química', 'Competencia 1: Utiliza conceptos, criterios, métodos y mecanismos de naturaleza científica para el desarrollo de procesos e investigaciones en el campo de la Química.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Química', 'Competencia 2: Utiliza información relacionada con la constitución, clasificación y organización de la materia, para la representación de las sustancias químicas presentes en su medio circundante.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Química', 'Competencia 3: Interpreta los cambios químicos que ocurren en la materia de su entorno inmediato a partir del empleo de fórmulas y ecuaciones químicas.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Química', 'Competencia 4: Interpreta los fenómenos que ocurren en sustancias gaseosas, las leyes y principios que los explican, así como el origen y la transferencia de energía entre sistemas termodinámicos a partir de las reacciones químicas que ocurren en su medio circundante.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Biología', 'Competencia 1: Aplica el conocimiento científico en la investigación y resolución de problemas del entorno.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Biología', 'Competencia 2: Integra información relacionada con la organización, estructura, mecanismos y funciones de los seres vivos para comprender la vida en sus diversas manifestaciones.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Biología', 'Competencia 3: Relaciona los principios de la herencia con las características observables en diferentes especies y con los cambios ocurridos como resultado de la evolución y adaptación al entorno.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Biología', 'Competencia 4: Relaciona el medio físico con los organismos que allí existen y la forma como éstos contribuyen al equilibrio del ecosistema.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Biología', 'Competencia 5: Aplica medidas que contribuyen a mantener la salud a nivel individual, familiar y de la comunidad.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Expresión Artística', 'Competencia 1: Explica y describe los lenguajes de las disciplinas artísticas básicas.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Expresión Artística', 'Competencia 2: Evidencia el desarrollo de habilidades relacionadas con la expresión artística a través de la creación, interpretación y ejecución de acciones artísticas.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Expresión Artística', 'Competencia 3: Analiza los roles y funciones de las artes en las culturas humanas a través de la historia.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Expresión Artística', 'Competencia 4: Explica los roles y funciones de las artes en las culturas de Guatemala.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Expresión Artística', 'Competencia 5: Demuestra habilidades específicas en una de las artes a través de la creación propia y la ejecución.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Seminario (Investigación-Acción)', 'Competencia 1: Construye explicaciones de su realidad producto de la profundización del autoconocimiento y la afirmación personal.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Seminario (Investigación-Acción)', 'Competencia 2: Desarrolla el pensamiento indagador y reflexivo como producto del manejo selectivo y riguroso de la información a la que accede y de las capacidades de análisis crítico de las fuentes consultadas.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Quinto Año', 'Seminario (Investigación-Acción)', 'Competencia 3: Estructura el proyecto de investigación interrelacionándolo con la dinámica social actual guatemalteca.', ARRAY[]::TEXT[]);
